use std::fs::File;
use std::io::{self, Read, Write};
use std::env;

fn main() -> io::Result<()> {
    // Get the file paths from command-line arguments
    let args: Vec<String> = env::args().collect();
    if args.len() < 3 {
        eprintln!("Usage: {} <input_binary_file> <output_text_file>", args[0]);
        return Ok(());
    }

    let input_file = &args[1];
    let output_file = &args[2];

    // Open the input binary file
    let mut file = File::open(input_file)?;
    let mut buffer = Vec::new();
    file.read_to_end(&mut buffer)?;

    // Convert the buffer to a vector of integers
    let integers: Vec<i32> = buffer
        .chunks_exact(4) // Assuming each integer is 4 bytes
        .map(|chunk| i32::from_ne_bytes(chunk.try_into().unwrap()))
        .collect();

    // Open the output text file
    let mut output = File::create(output_file)?;

    // Write the integers to the output file, each on a new line
    for integer in integers {
        writeln!(output, "{}", integer)?;
    }

    println!("Data has been successfully written to {}", output_file);
    Ok(())
}
```

